// n8n Code node (JavaScript) - NormalizeText
// Input: items[] where each item.json is an inbound_receipts row
// Output: same items with normalized_text, input_hash, input_excerpt, normalize_debug

const crypto = require('crypto');

function htmlToText(html) {
  if (!html) return '';
  let t = html;

  t = t.replace(/<script[\s\S]*?<\/script>/gi, ' ');
  t = t.replace(/<style[\s\S]*?<\/style>/gi, ' ');

  t = t.replace(/<(br|br\/)\s*>/gi, '\n');
  t = t.replace(/<\/(p|div|tr|li|h1|h2|h3|h4|h5|h6|table)>/gi, '\n');

  t = t.replace(/<a [^>]*href="([^"]+)"[^>]*>([\s\S]*?)<\/a>/gi, (m, href, inner) => {
    const innerText = inner.replace(/<[^>]+>/g, '').trim();
    if (!innerText) return href;
    return innerText;
  });

  t = t.replace(/<[^>]+>/g, ' ');

  t = t
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&#39;/g, "'")
    .replace(/&quot;/gi, '"');

  return t;
}

function normalizeWhitespace(text) {
  let t = (text || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  t = t.split('\n').map(l => l.replace(/[ \t]+$/g, '')).join('\n');
  t = t.replace(/\n{3,}/g, '\n\n');
  return t.trim();
}

/**
 * If the message contains one or more "Forwarded message" blocks,
 * keep the innermost (last) forwarded content.
 */
function extractInnermostForwarded(text) {
  if (!text) return '';

  const markerRe = /^-{5,}\s*Forwarded message\s*-{5,}$/gim;
  const matches = [...text.matchAll(markerRe)];
  if (matches.length === 0) return text;

  const last = matches[matches.length - 1];
  const startIdx = (last && typeof last.index === 'number') ? last.index : 0;
  const tail = text.slice(startIdx);

  // If the tail doesn't look like a receipt/subscription notice, fall back.
  const signalRe = /(receipt|order summary|invoice|subscription|renewed|total paid|billed to)/i;
  if (!signalRe.test(tail)) return text;

  return tail;
}

/**
 * Remove the leading forward/reply header stanza ("From:", "Date:", "Subject:", "To:")
 * near the top of the message (often repeated by Gmail forwards).
 */
function stripLeadingForwardHeaders(text) {
  if (!text) return '';

  const lines = text.split('\n');
  let i = 0;

  // Skip the forwarded marker if present
  if (/^-{5,}\s*Forwarded message\s*-{5,}$/i.test((lines[0] || '').trim())) i = 1;

  // Remove a short run of "From/Date/Subject/To" lines at the top
  let removedAny = false;
  while (i < Math.min(lines.length, 20)) {
    const line = (lines[i] || '').trim();
    if (!line) { i++; continue; }

    if (/^(From|Date|Subject|To):\s/i.test(line)) {
      removedAny = true;
      i++;
      continue;
    }
    break;
  }

  if (!removedAny) return text;

  // Also drop blank lines after headers
  while (i < lines.length && !lines[i].trim()) i++;

  return lines.slice(i).join('\n');
}

function stripQuotedChains(text) {
  if (!text) return '';

  const lines = text.split('\n');

  const cutPatterns = [
    /^On .+wrote:$/i,
    /^-+Original Message-+$/i,
    /^_{5,}$/i,
    /^>+/,
  ];

  let cutIndex = -1;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;

    // Gmail forwarded header
    if (/^-{5,}\s*Forwarded message\s*-{5,}$/i.test(line)) {
      // Keep forwarded content (often what we want), so do NOT cut here.
      continue;
    }

    // Typical reply header blocks: "On ... wrote:" later in the email
    if (cutPatterns.some(re => re.test(line)) && i > 20) {
      cutIndex = i;
      break;
    }

    // If we hit a classic multi-line reply header set later (From/Sent/To/Subject),
    // cut only if it appears deep in the message.
    if (i > 25 && /^(From|Sent|To|Subject):\s/i.test(line)) {
      cutIndex = i;
      break;
    }
  }

  if (cutIndex >= 0) return lines.slice(0, cutIndex).join('\n');
  return text;
}

function removeCommonBoilerplate(text) {
  if (!text) return '';

  const boilerplatePatterns = [
    /unsubscribe/i,
    /manage your (email )?preferences/i,
    /view (this|email) in (a )?browser/i,
    /privacy policy/i,
    /terms (and|&) conditions/i,
    /all rights reserved/i,
    /do not reply/i,
  ];

  const lines = text.split('\n');
  const kept = [];

  for (const raw of lines) {
    const line = raw.trim();

    if (line.length > 240 && /^https?:\/\//i.test(line)) continue;

    const urlCount = (line.match(/https?:\/\//gi) || []).length;
    if (urlCount >= 2 && line.length > 120) continue;

    if (line.length < 140 && boilerplatePatterns.some(re => re.test(line))) continue;

    kept.push(raw);
  }

  return kept.join('\n');
}

function stripSignatureBlock(text) {
  if (!text) return '';

  const lines = text.split('\n');
  const sigMarkers = [
    /^--\s*$/,
    /^sent from my/i,
    /^best,?$/i,
    /^thanks,?$/i,
    /^regards,?$/i,
    /^sincerely,?$/i,
  ];

  for (let i = 10; i < lines.length; i++) {
    const line = lines[i].trim();
    if (sigMarkers.some(re => re.test(line))) {
      return lines.slice(0, i).join('\n');
    }
  }
  return text;
}

function compact(text, maxChars) {
  if (!text) return '';
  if (text.length <= maxChars) return text;

  const slice = text.slice(0, maxChars);
  const lastBreak = Math.max(slice.lastIndexOf('\n\n'), slice.lastIndexOf('\n'));
  if (lastBreak > maxChars * 0.7) return slice.slice(0, lastBreak).trim();
  return slice.trim();
}

const MAX_CHARS = 12000;

return items.map((item) => {
  const row = item.json || {};

  // Choose base text
  let baseText = (row.body_text && String(row.body_text).trim()) ? String(row.body_text) : '';
  if (!baseText && row.body_html) {
    baseText = htmlToText(String(row.body_html));
  }

  baseText = normalizeWhitespace(baseText);

  // Prefer the innermost forwarded receipt content (Gmail forwards often nest twice)
  baseText = extractInnermostForwarded(baseText);
  baseText = stripLeadingForwardHeaders(baseText);

  let cleaned = stripQuotedChains(baseText);

  cleaned = removeCommonBoilerplate(cleaned);
  cleaned = stripSignatureBlock(cleaned);

  cleaned = normalizeWhitespace(cleaned);

  // Prepend minimal metadata to help downstream extraction (prototype-critical)
  const headerLines = [
    row.subject ? `Subject: ${String(row.subject).trim()}` : null,
    row.from_email ? `From: ${String(row.from_email).trim()}` : null,
    row.from_domain ? `From-Domain: ${String(row.from_domain).trim()}` : null,
    row.to_email ? `To: ${String(row.to_email).trim()}` : null,
  ].filter(Boolean).join('\n');

  const normalized_body = compact(cleaned, MAX_CHARS);
  const normalized_text = headerLines ? `${headerLines}\n\n${normalized_body}` : normalized_body;

  const input_hash = crypto.createHash('sha256').update(normalized_text || '', 'utf8').digest('hex');
  const input_excerpt = (normalized_text || '').slice(0, 800);

  return {
    json: {
      ...row,
      normalized_text,
      input_hash,
      input_excerpt,
      normalize_debug: {
        had_body_text: !!(row.body_text && String(row.body_text).trim()),
        had_body_html: !!(row.body_html && String(row.body_html).trim()),
        original_len: baseText.length,
        normalized_len: normalized_text.length,
        max_chars: MAX_CHARS,
        used_innermost_forwarded: true,
      },
    },
  };
});

