function buildUpdatePolicy(existing, incoming, docDate) {
  const existingLast = toDate(existing?.last_observed_content_date);
  const incomingDoc = toDate(docDate);

  // If no incoming doc date, default to "update all non-empty" (but we will still set last_observed_content_date if provided)
  let mode = "all_non_empty";
  if (incomingDoc && existingLast) {
    if (incomingDoc > existingLast) mode = "all_non_empty";
    else mode = "missing_only";
  } else if (incomingDoc && !existingLast) {
    mode = "all_non_empty";
  } else if (!incomingDoc && existingLast) {
    mode = "missing_only";
  }

  const fields = [
    "display_name","plan_name","provider_name","provider_domain",
    "billed_by_name","billed_by_domain","status",
    "billing_cadence","amount","currency",
    "next_renewal_at","last_billed_at","cancel_by_at","trial_ends_at",
    "source","confidence","notes",
    "last_observed_content_date","last_source_receipt_id","last_source_type",
    "reminder_enabled","reminder_days","notify_channels",
  ];

  const upd = {};
  for (const f of fields) {
    const incomingVal = incoming?.[f];
    if (mode === "all_non_empty") {
      if (!isEmpty(incomingVal)) upd[f] = incomingVal;
    } else {
      // missing_only: only fill if existing is empty AND incoming has value
      const existingVal = existing?.[f];
      if (isEmpty(existingVal) && !isEmpty(incomingVal)) upd[f] = incomingVal;
    }
  }

  // Always keep pod_id stable
  if (existing?.pod_id) upd.pod_id = existing.pod_id;

  // Always set last_observed_content_date if incomingDoc exists and:
  // - mode = all_non_empty (doc newer) -> set it
  // - mode = missing_only (doc older) -> only set if existing missing (handled above)
  return { update: Object.keys(upd).length ? upd : null, mode, existingLast: existingLast?.toISOString?.() ?? null, incomingDoc: incomingDoc?.toISOString?.() ?? null };
}

