/**
 * PostWriteResponse (for Mail Parser)
 * ----------------------------------
 * This Code node is wired to receive:
 *  - success output from "Insert Subscription" (Supabase create row), OR
 *  - success output from "HTTP Request" (PATCH), OR
 *  - (optionally) the fallback/skip branch from the Switch
 *
 * It returns ONE unified payload back to the caller (Adapter), including:
 *  - inbound_receipt_patch: fields the Adapter should PATCH onto inbound_receipts
 *  - parser_run_patch: fields the Adapter should PATCH onto parser_runs
 *  - decision + resolved_subscription_id
 *
 * Assumptions:
 *  - DSW node name: "Decide Subscription Write"
 *  - Mail row node name: "Fetch Mail Content"
 *  - Validate node name: "Validate Extract" (optional; used for suggested status)
 */

function first(arr) {
  return Array.isArray(arr) && arr.length ? arr[0] : null;
}

function pick(...vals) {
  for (const v of vals) if (v !== null && v !== undefined && v !== "") return v;
  return null;
}

function isObj(x) {
  return x && typeof x === "object" && !Array.isArray(x);
}

function nowIso() {
  return new Date().toISOString();
}

// Try to extract a created/updated subscription id from a variety of node outputs
function extractSubIdFromWriteNodeJson(j) {
  if (!j) return null;

  // Common shapes:
  // - Supabase create: { id: "uuid", ... }
  if (typeof j.id === "string") return j.id;

  // - Supabase create sometimes returns { data: [{ id }], ... }
  if (Array.isArray(j.data) && j.data[0]?.id) return j.data[0].id;

  // - HTTP Request might return the updated row (if "Return full response" or API returns body)
  if (isObj(j.body)) {
    if (typeof j.body.id === "string") return j.body.id;
    if (Array.isArray(j.body) && j.body[0]?.id) return j.body[0].id;
  }

  // - HTTP Request might return { data: {...} }
  if (isObj(j.data) && typeof j.data.id === "string") return j.data.id;
  if (Array.isArray(j.data) && j.data[0]?.id) return j.data[0].id;

  return null;
}

// Derive a compact write_reason string
function buildWriteReason(dsw) {
  const action = dsw?.action ?? "unknown";
  const mode = dsw?.__diag_dsw?.update_mode ?? null;

  if (action === "insert") return "new subscription inserted";
  if (action === "update") return mode ? `existing subscription updated (${mode})` : "existing subscription updated";
  if (action === "skip") {
    if (dsw?.debug?.matched) return mode ? `matched existing; no fields to update (${mode})` : "matched existing; no fields to update";
    return "no write performed";
  }
  return "no write performed";
}

// Decide parser_run status suggestion
function deriveParserRunStatus(dsw, validateExtractJson) {
  // Prefer explicit suggestion if present
  const suggested = validateExtractJson?.parser_run_status_suggested;
  if (suggested) return suggested;

  // Otherwise infer
  const extractValid = dsw?.__diag_dsw?.validate_extract_valid;
  if (extractValid === false) return "error";

  const classification = dsw?.debug?.classification ?? null;

  // If you only run this workflow for subscription-like content, most non-errors are success/partial/no_signal.
  if (!classification) return "partial";

  if (classification === "spam") return "skipped";
  if (classification === "not_subscription") return "no_signal";
  if (classification === "maybe_subscription") return "partial";

  // classification === "subscription"
  return "success";
}

function deriveInboundReceiptParserStatus(parserRunStatus) {
  // Keep the same vocabulary to avoid extra mapping logic in Adapter
  return parserRunStatus || "partial";
