}

function nowIso() {
  return new Date().toISOString();
}

function stringifyError(e) {
  if (!e) return null;
  if (typeof e === "string") return e;
  if (e.message) return String(e.message);
  try {
    return JSON.stringify(e);
  } catch {
    return String(e);
  }
}

function extractErrorFromInputJson(j) {
  // n8n error shapes vary; try a few common ones
  return {
    errorMessage: pick(j?.errorMessage, j?.message, j?.error?.message, j?.cause?.message, null),
    errorName: pick(j?.errorName, j?.name, j?.error?.name, null),
    errorCode: pick(j?.errorCode, j?.code, j?.error?.code, null),
    errorDetails: j?.errorDetails ?? j?.error ?? null,
    n8nDetails: j?.n8nDetails ?? null,
  };
}

// ------------------------------- main ---------------------------------

// Merge node will output 1+ items depending on how you configured it.
// We want the "best" error: prefer one with errorMessage present.
const inputs = $input.all().map(i => i?.json ?? {});
let best = inputs.find(j => j?.errorMessage || j?.message || j?.error) ?? (inputs[0] ?? {});

// Pull DSW + Mail Content context for enrichment
let dsw = null;
try { dsw = first($items("Decide Subscription Write"))?.json ?? null; } catch (_) {}
let mail = null;
try { mail = first($items("Fetch Mail Content"))?.json ?? null; } catch (_) {}

const action = dsw?.action ?? "unknown";
const matchedId = dsw?.matched_subscription_id ?? null;

const err = extractErrorFromInputJson(best);
const errorMessage = pick(err.errorMessage, "Write failed");
const errorCode = pick(err.errorCode, err.errorName, "write_failed");

// Keep error_detail bounded (Supabase column is text; keep it short-ish)
const errorDetailObj = {
  errorMessage,
  errorCode,
  errorName: err.errorName ?? null,
  action,
  matched_subscription_id: matchedId,
  node_hint: best?.node ?? best?.nodeName ?? null,
  // Keep a light trace; remove if too noisy
  n8nDetails: err.n8nDetails ? {
    n8nVersion: err.n8nDetails?.n8nVersion ?? null,
    stackTrace: err.n8nDetails?.stackTrace?.slice?.(0, 6) ?? null,
  } : null,
};

let errorDetail;
try {
  errorDetail = JSON.stringify(errorDetailObj);
} catch (e) {
  errorDetail = stringifyError(errorDetailObj) ?? stringifyError(e) ?? "write_failed";
}

// What Adapter should PATCH onto inbound_receipts on failure
const inbound_receipt_patch = {
  parser_status: "error",
  processed_at: nowIso(),
  error_code: errorCode,
  error_detail: errorDetail,

  // Helpful partial enrichment (safe even on failure)
  content_date: pick(dsw?.__diag_dsw?.doc_date_used, mail?.content_date, mail?.received_at, null),
  resolved_subscription_id: matchedId, // best we can do on update failure
  write_decision: action,
  write_reason: "write failed",
};

// What Adapter should PATCH onto parser_runs on failure
const parser_run_patch = {
  status: "error",
  classification: dsw?.debug?.classification ?? null,
  confidence: null,

  matched_subscription_id: matchedId,
  resolved_subscription_id: matchedId,
  write_decision: action,
  write_reason: "write failed",

  error_code: errorCode,
  error_detail: errorDetail,
};

return [
  {
    json: {
      ok: false,
      action,
      inbound_receipt_id: mail?.id ?? null,
      pod_id: mail?.pod_id ?? null,
      matched_subscription_id: matchedId,
      resolved_subscription_id: matchedId,

      error_code: errorCode,
      error_message: errorMessage,
      error_detail: errorDetail,

      inbound_receipt_patch,
      parser_run_patch,

      // preserve upstream diagnostics for debugging
      __diag_dsw: dsw?.__diag_dsw ?? null,
    },
  },
];
